class Rum():

  def __init__(self, storlek, fönster, uthyrt=False):
    self.storlek = storlek
    self.antal_fönster = fönster
    self.uthyrt = uthyrt

  def __str__(self):
    if self.uthyrt:
      sträng = "Rummet är uthyrt: "
    else:
      sträng = "Rummet är ledigt: "

    return sträng + str(self.storlek) + " kvm stort och har " + str(self.antal_fönster) + " fönster."

  def hyr_ut(self):
    self.uthyrt = True

  def är_ledigt(self):
    self.uthyrt = False


class Rum_med_Pentry(Rum):

  def utrustning(self, ugn=True, micro=True ):
    self.ugn = ugn
    self.micro = micro


def main():
  rum = Rum(16, 1, False)
  print(rum)  
  rum2 = Rum_med_Pentry(20, 1, True)
  print(rum2)

  rum2.utrustning(False, True) #Sätter de ny attributen 
  print("Ugn:", rum2.ugn, "Micro:", rum2.micro) #Skriver ut de

main()
